const body = $json.body || $json;
const hasImage = !!(body.has_image && body.image_base64);
const requestedMode = String(body.policy_mode || 'balanced').trim().toLowerCase();
const policyMode = ['conservative', 'balanced', 'aggressive'].includes(requestedMode) ? requestedMode : 'balanced';
return [{ json: {
  request_id: 'r-' + Date.now(),
  prompt: body.prompt || '',
  policy_mode: policyMode,
  dept_id: body.dept_id || 'demo-support',
  task_type: body.task_type || 'general',
  has_image: hasImage,
  image_filename: body.image_filename || null,
  image_base64: body.image_base64 || null
} }];

const norm = $('Normalize').item.json;
const guard = $('Guardrails').item.json;

function safeItems(name) { try { return $items(name); } catch (e) { return []; } }
let cacheConf = 0;
const _cacheItems = safeItems('Cache Lookup');
if (_cacheItems.length) { cacheConf = _cacheItems[0].json.confidence || 0; }

let hasImage = !!norm.has_image;
let imageClass = null;
let imageComplexity = 0;
const _imgItems = (typeof safeItems === 'function' ? safeItems : (function(name){ try { return $items(name); } catch (e) { return []; } }))('Image Analyser');
if (_imgItems.length) {
  const img = _imgItems[0].json;
  imageClass = img.class;
  imageComplexity = img.visual_complexity || 0;
}

return [{ json: {
  request_id: norm.request_id,
  prompt: guard.safe_text || norm.prompt,
  policy_mode: norm.policy_mode,
  guardrail_status: 'passed',
  guardrail_reason: guard.reason || 'passed',
  cache_status: hasImage ? 'skipped' : 'miss',
  cache_confidence: cacheConf,
  contains_sensitive_data: guard.contains_sensitive_data || false,
  require_local_model: guard.require_local_model || false,
  allow_external_model: guard.allow_external_model !== false,
  prefer_low_cost_tier: guard.prefer_low_cost_tier || false,
  estimated_tokens: guard.estimated_tokens || 0,
  has_image: hasImage,
  image_class: imageClass || '',
  image_complexity: imageComplexity || 0
} }];

function safeItems(name) { try { return $items(name); } catch (e) { return []; } }
const outGuard = $json;
const _cItems = safeItems('Cache Lookup');
const cache = _cItems.length ? _cItems[0].json : { confidence: 0, entry_id: null, answer: null, estimated_tokens: 0, cost_saved: 0 };
const guardrail = $('Guardrails').item.json;
const cachedAnswer = cache.answer;

let answer;
let outStatus;
if (outGuard.pass === false) {
  answer = 'The generated response was blocked by the output guardrail.';
  outStatus = 'blocked';
} else {
  answer = (outGuard.redacted_text && outGuard.redacted_text !== cachedAnswer) ? outGuard.redacted_text : cachedAnswer;
  outStatus = 'passed';
}

return [{ json: {
  answer: answer,
  receipt: {
    guardrail_status: 'passed',
    output_guardrail_status: outStatus,
    output_guardrail_issues: outGuard.issues || [],
    cache_status: 'hit',
    cache_confidence: cache.confidence,
    cache_entry_id: cache.entry_id,
    selected_tier: 'cache',
    estimated_tokens: (cache.estimated_tokens != null ? cache.estimated_tokens : 0),
    estimated_cost: 0,
    optimization_reason: 'semantic_cache_hit',
    cost_saved: (cache.cost_saved != null ? cache.cost_saved : 0),
    detected_risk_type: guardrail.detected_risk_type || null,
    reason: 'semantic_cache_hit',
    savings_source: 'semantic_cache',
    savings_reason: 'semantic_cache_hit',
    provider: 'not called — semantic cache',
    model: '-',
    requested_tier: 'cache',
    executed_tier: 'cache'
  }
} }];

function safeItems(name) { try { return $items(name); } catch (e) { return []; } }
const outGuard = $('Guardrails Output').item.json;
const optimizer = $('Optimizer').item.json;
const guardrail = $('Guardrails').item.json;
const _cItems = safeItems('Cache Lookup');
const cache = _cItems.length ? _cItems[0].json : { confidence: 0, entry_id: null, answer: null, estimated_tokens: 0, cost_saved: 0 };
const provider = $('Provider Execute').item.json;
const modelAnswer = provider.answer;

let answer;
let outStatus;
if (outGuard.pass === false) {
  answer = 'The generated response was blocked by the output guardrail.';
  outStatus = 'blocked';
} else {
  answer = (outGuard.redacted_text && outGuard.redacted_text !== modelAnswer) ? outGuard.redacted_text : modelAnswer;
  outStatus = 'passed';
}

const inStatus = guardrail.requires_redaction ? 'passed_with_redaction' : 'passed';
const savingsReason = provider.used_fallback ? 'provider_fallback' : 'cheaper_model_selected';

return [{ json: {
  answer: answer,
  receipt: {
    policy_mode: optimizer.policy_mode,
    guardrail_status: inStatus,
    output_guardrail_status: outStatus,
    output_guardrail_issues: outGuard.issues || [],
    cache_status: 'miss',
    cache_confidence: (cache.confidence != null ? cache.confidence : 0),
    cache_entry_id: null,
    selected_tier: optimizer.selected_tier,
    estimated_tokens: optimizer.estimated_tokens,
    estimated_cost: optimizer.estimated_cost,
    optimization_reason: optimizer.optimization_reason,
    cost_saved: optimizer.cost_saved,
    detected_risk_type: guardrail.detected_risk_type || null,
    reason: guardrail.reason || 'passed',
    savings_source: 'model_routing',
    savings_reason: savingsReason,
    task_type: optimizer.task_type,
    complexity_score: optimizer.complexity_score,
    complexity_level: optimizer.complexity_level,
    compression_recommended: optimizer.compression_recommended,
    compression_target_ratio: optimizer.compression_target_ratio,
    compression_reason: optimizer.compression_reason,
    compression_risk: optimizer.compression_risk,
    fallback_tier: optimizer.fallback_tier,
    estimated_baseline_cost: optimizer.estimated_baseline_cost,
    estimated_optimized_cost: optimizer.estimated_optimized_cost,
    decision_reasons: optimizer.decision_reasons || [],
    graph_path: optimizer.graph_path,
    branch_reason: optimizer.branch_reason,
    executed_nodes: optimizer.executed_nodes || [],
    provider: provider.provider,
    model: provider.model,
    requested_tier: provider.requested_tier,
    executed_tier: provider.executed_tier,
    actual_input_tokens: provider.actual_input_tokens,
    actual_output_tokens: provider.actual_output_tokens,
    actual_total_tokens: provider.actual_total_tokens,
    actual_cost: provider.actual_cost,
    actual_cost_saved: provider.actual_cost_saved,
    latency_ms: provider.latency_ms,
    used_fallback: provider.used_fallback,
    fallback_reason: provider.fallback_reason,
    privacy_enforced: provider.privacy_enforced,
    cost_calculation_status: provider.cost_calculation_status,
    actual_execution_attempt_count: provider.actual_execution_attempt_count,
    prompt_redaction_applied: provider.prompt_redaction_applied || guardrail.requires_redaction || false,
    provider_attempts: (provider.attempts || []).map(a => a.provider + '/' + a.tier + ' ' + (a.attempt_role || 'primary') + (a.executed ? ' executed' : ' skipped') + (a.success ? ' ok' : ' fail:' + (a.error_code || '')))
  }
} }];

const g = $json;
const tokens = (g.estimated_tokens != null) ? g.estimated_tokens : 0;
const saved = g.cost_saved_by_blocking || 0;
return [{ json: {
  answer: 'Request blocked by MomiHelm guardrails: ' + (g.reason || 'blocked'),
  receipt: {
    guardrail_status: 'blocked',
    output_guardrail_status: 'skipped',
    output_guardrail_issues: [],
    cache_status: 'skipped',
    cache_confidence: 0,
    cache_entry_id: null,
    selected_tier: 'none',
    estimated_tokens: tokens,
    estimated_cost: 0,
    optimization_reason: 'Blocked: ' + (g.reason || '') + (g.policy_triggered ? ' [' + g.policy_triggered + ']' : ''),
    cost_saved: saved,
    detected_risk_type: g.detected_risk_type || null,
    reason: g.reason || 'blocked',
    savings_source: 'guardrails_cost_governance',
    savings_reason: g.reason || 'blocked',
    provider: 'not called — guardrail block',
    model: '-'
  }
} }];

function safeItems(name) {
  try { return $items(name); } catch (e) { return []; }
}
const body = $json;
const receipt = body.receipt || {};
const norm = $('Normalize').item.json;
const guardItems = safeItems('Guardrails');
const guard = guardItems.length ? guardItems[0].json : {};
const optItems = safeItems('Optimizer');
const optimizer = optItems.length ? optItems[0].json : {};

let status = 'completed';
if (receipt.guardrail_status === 'blocked') status = 'blocked';
else if (receipt.output_guardrail_status === 'blocked') status = 'output_blocked';
else if (receipt.error_code) status = 'provider_failed';

const promptForFingerprint = guard.safe_text || norm.prompt || '';
const baseline = receipt.estimated_baseline_cost != null ? receipt.estimated_baseline_cost : (optimizer.estimated_baseline_cost || receipt.cost_saved || 0);
const optimized = receipt.estimated_optimized_cost != null ? receipt.estimated_optimized_cost : (optimizer.estimated_optimized_cost || 0);
const estimatedSavings = receipt.cost_saved != null ? receipt.cost_saved : (optimizer.cost_saved || 0);

return [{ json: {
  answer: body.answer,
  receipt: receipt,
  usage_log: {
    request_id: norm.request_id,
    dept_id: norm.dept_id,
    policy_mode: optimizer.policy_mode || norm.policy_mode,
    prompt: promptForFingerprint,
    task_type: receipt.task_type || optimizer.task_type || norm.task_type || 'general',
    complexity_level: receipt.complexity_level || optimizer.complexity_level || null,
    guardrail_status: receipt.guardrail_status || 'passed',
    guardrail_reason: receipt.reason || guard.reason || null,
    detected_risk_type: receipt.detected_risk_type || guard.detected_risk_type || null,
    cache_status: receipt.cache_status || 'miss',
    cache_confidence: receipt.cache_confidence || 0,
    graph_path: receipt.graph_path || optimizer.graph_path || null,
    status: status,
    provider: receipt.provider || null,
    model: receipt.model || null,
    requested_tier: receipt.requested_tier || receipt.selected_tier || null,
    executed_tier: receipt.executed_tier || null,
    actual_input_tokens: receipt.actual_input_tokens || 0,
    actual_output_tokens: receipt.actual_output_tokens || 0,
    actual_total_tokens: receipt.actual_total_tokens || 0,
    actual_cost: receipt.actual_cost,
    cost_calculation_status: receipt.cost_calculation_status || null,
    latency_ms: receipt.latency_ms || 0,
    used_fallback: receipt.used_fallback || false,
    fallback_reason: receipt.fallback_reason || null,
    privacy_enforced: receipt.privacy_enforced || false,
    actual_execution_attempt_count: receipt.actual_execution_attempt_count || 0,
    savings_source: receipt.savings_source || 'unknown',
    savings_reason: receipt.savings_reason || null,
    estimated_baseline_cost: baseline,
    estimated_optimized_cost: optimized,
    estimated_savings: estimatedSavings,
    actual_cost_saved: receipt.actual_cost_saved,
    output_guardrail_status: receipt.output_guardrail_status || 'skipped',
    output_guardrail_issues: receipt.output_guardrail_issues || []
  }
} }];
